type statusPageJoins[Q dialect.Joinable] struct {
	typ                    string
	Groups                 modAs[Q, groupColumns]
	Incidents              modAs[Q, incidentColumns]
	MaintenanceStatusPages modAs[Q, maintenanceStatusPageColumns]
	StatusPageCnames       modAs[Q, statusPageCnameColumns]
}

func (j statusPageJoins[Q]) aliasedAs(alias string) statusPageJoins[Q] {
	return buildStatusPageJoins[Q](buildStatusPageColumns(alias), j.typ)
}

func buildStatusPageJoins[Q dialect.Joinable](cols statusPageColumns, typ string) statusPageJoins[Q] {
	return statusPageJoins[Q]{
		typ: typ,
		Groups: modAs[Q, groupColumns]{
			c: Groups.Columns,
			f: func(to groupColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Groups.Name().As(to.Alias())).On(
						to.StatusPageID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		Incidents: modAs[Q, incidentColumns]{
			c: Incidents.Columns,
			f: func(to incidentColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Incidents.Name().As(to.Alias())).On(
						to.StatusPageID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		MaintenanceStatusPages: modAs[Q, maintenanceStatusPageColumns]{
			c: MaintenanceStatusPages.Columns,
			f: func(to maintenanceStatusPageColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, MaintenanceStatusPages.Name().As(to.Alias())).On(
						to.StatusPageID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		StatusPageCnames: modAs[Q, statusPageCnameColumns]{
			c: StatusPageCnames.Columns,
			f: func(to statusPageCnameColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, StatusPageCnames.Name().As(to.Alias())).On(
						to.StatusPageID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
